const parent = { familyName: 'Smith' };
const child = Object.create(parent);
child.firstName = 'John';

// The 'in' operator checks the whole chain
console.log('familyName' in child); // true

// Object.hasOwn only checks the object itself
console.log(Object.hasOwn(child, 'firstName'));  // true
console.log(Object.hasOwn(child, 'familyName')); // false
